import{_ as s,o as n,c as e,ag as t}from"./chunks/framework.BZohXCq9.js";const u=JSON.parse('{"title":"Trend 工作流","description":"","frontmatter":{},"headers":[],"relativePath":"workflows/trend.md","filePath":"workflows/trend.md"}'),p={name:"workflows/trend.md"};function i(l,a,d,r,c,o){return n(),e("div",null,[...a[0]||(a[0]=[t(`<h1 id="trend-工作流" tabindex="-1">Trend 工作流 <a class="header-anchor" href="#trend-工作流" aria-label="Permalink to &quot;Trend 工作流&quot;">​</a></h1><p><strong>一句话：热点来了，先判断该不该跟，再决定怎么跟。</strong></p><hr><h2 id="什么时候该用这个" tabindex="-1">什么时候该用这个 <a class="header-anchor" href="#什么时候该用这个" aria-label="Permalink to &quot;什么时候该用这个&quot;">​</a></h2><p>你正在刷微博，看到「OpenAI 发布了新模型」上了热搜。</p><p>你正在刷小红书，看到一个话题突然爆了。</p><p>你正在看新闻，看到某个事件在朋友圈刷屏了。</p><p>这些时刻的共同点是：<strong>热点来了，而且来得很急。</strong></p><p>热点之所以叫热点，就是它来得快、去得也快。你需要在短时间内判断：</p><ul><li>这个热点跟我的账号定位搭不搭？</li><li>我能从什么角度切入？</li><li>到底值不值得跟？</li><li>强行蹭的话，风险是什么？</li></ul><p><strong>Trend 工作流就是帮你完成这个「快速判断 + 快速产出」的过程。</strong></p><p>它不是让你盲目追热点，而是让你在热潮中保持冷静——先分析适切性，再决定要不要动手。</p><h3 id="适合-trend-的场景" tabindex="-1">适合 Trend 的场景 <a class="header-anchor" href="#适合-trend-的场景" aria-label="Permalink to &quot;适合 Trend 的场景&quot;">​</a></h3><ul><li>热搜上出现跟你领域相关的热点</li><li>行业里有了新动态，你想快速响应</li><li>某个事件在社交媒体上刷屏了</li><li>你想测试一下某个角度有没有人看</li></ul><h3 id="不适合-trend-的场景" tabindex="-1">不适合 Trend 的场景 <a class="header-anchor" href="#不适合-trend-的场景" aria-label="Permalink to &quot;不适合 Trend 的场景&quot;">​</a></h3><ul><li>你已经有明确的系列计划 → 用 Campaign</li><li>你只是想记录一个想法 → 用 Quick</li><li>这个热点跟你八竿子打不着 → 别跟，浪费时间</li></ul><hr><h2 id="一个完整的创作故事" tabindex="-1">一个完整的创作故事 <a class="header-anchor" href="#一个完整的创作故事" aria-label="Permalink to &quot;一个完整的创作故事&quot;">​</a></h2><p>让我带你走一遍 Trend 的完整流程。</p><h3 id="第一步-发现热点" tabindex="-1">第一步：发现热点 <a class="header-anchor" href="#第一步-发现热点" aria-label="Permalink to &quot;第一步：发现热点&quot;">​</a></h3><p>早上九点，你刷微博，看到「OpenAI 发布了新模型」上了热搜。你是一个写 AI 效率方向的博主，这个热点必须得蹭。</p><p>但你没有立刻开始写。因为你被热点伤过——之前有一次你追了一个热点，写了两个小时，结果发出去没人看，还被读者评论说「硬蹭」。</p><p>你决定用工作流来说话。</p><h3 id="第二步-发起热点" tabindex="-1">第二步：发起热点 <a class="header-anchor" href="#第二步-发起热点" aria-label="Permalink to &quot;第二步：发起热点&quot;">​</a></h3><p>你打开 Claude Code，说：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/xhs:hot</span></span>
<span class="line"><span></span></span>
<span class="line"><span>主题：OpenAI 新模型发布</span></span>
<span class="line"><span>来源：发布会摘要</span></span>
<span class="line"><span>紧急度：high</span></span></code></pre></div><p>AI 没有立刻开始写稿，而是先问了你几个问题：</p><ul><li>这个热点你打算从哪个角度切入？（技术解读 / 效率提升 / 普通人怎么用）</li><li>你的目标受众是谁？（技术人员 / 产品经理 / 普通用户）</li><li>你想达到什么效果？（展示专业度 / 引流 / 纯蹭热度）</li></ul><p>你回答完之后，AI 说：「好，我帮你创建 Trend 工作流。」</p><h3 id="第三步-fit-check-最关键的环节" tabindex="-1">第三步：fit-check（最关键的环节） <a class="header-anchor" href="#第三步-fit-check-最关键的环节" aria-label="Permalink to &quot;第三步：fit-check（最关键的环节）&quot;">​</a></h3><p>AI 读取了你的 brand 配置，生成了两个关键文档：</p><ul><li><strong>trend-brief.md</strong>：这个热点的基本信息——发生了什么、为什么重要</li><li><strong>fit-check.md</strong>：适切性判断——这个热点跟你的账号搭不搭</li></ul><p>你打开 fit-check 仔细看：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## 适切性分析</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### 相关性评估</span></span>
<span class="line"><span>- 领域相关度：高</span></span>
<span class="line"><span>- 受众匹配度：高</span></span>
<span class="line"><span>- 时间窗口：短（48小时内最佳）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### 风险提示</span></span>
<span class="line"><span>- 发布会信息铺天盖地，你的角度需要差异化</span></span>
<span class="line"><span>- 已经有大量同类内容产出，你需要找到独特切入点</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### 建议角度</span></span>
<span class="line"><span>1. 「普通人怎么用这个新模型提升效率」——差异化角度，避开技术解读的红海</span></span>
<span class="line"><span>2. 「这个新功能让我的一天发生了什么变化」——场景化，更容易引发共鸣</span></span>
<span class="line"><span>3. 「和上一代对比，这些变化值得你升级吗」——对比测评，实用导向</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### 结论</span></span>
<span class="line"><span>建议跟，但角度要选好，不要硬蹭技术细节</span></span></code></pre></div><p>你觉得这个分析很在理。特别是「差异化角度」那部分，点醒了你——如果你也去写技术解读，肯定拼不过那些专业AI媒体。</p><p>于是你说：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/xhs:fit approved</span></span></code></pre></div><p>热点通过了 fit-check，现在可以进入正稿阶段。</p><h3 id="第四步-创作" tabindex="-1">第四步：创作 <a class="header-anchor" href="#第四步-创作" aria-label="Permalink to &quot;第四步：创作&quot;">​</a></h3><p>你说：「继续写这篇，角度选第一个——普通人怎么用新模型提升效率。」</p><p>AI 生成了初稿。你快速审核了一下，发现开头太平淡了，于是说：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/xhs:review</span></span></code></pre></div><p>审核意见出来了：</p><ul><li>开头太长了，应该直接切入场景</li><li>「效率提升」这个词太抽象，应该用具体例子</li><li>CTA 要明确：引导读者去评论区分享他们的用法</li></ul><p>你把这些意见告诉 AI，让它改写。改完之后你看了一遍，觉得 OK 了。</p><h3 id="第五步-发布" tabindex="-1">第五步：发布 <a class="header-anchor" href="#第五步-发布" aria-label="Permalink to &quot;第五步：发布&quot;">​</a></h3><p>你说：「帮我生成发布包。」</p><p>AI 生成了一套完整的发布包。封面的方向是「效率党必看」，配图建议是做一张新旧模型对比的信息卡——这正好是你擅长做的内容类型。</p><p>你说：「归档这次创作。」</p><p>AI 把整个过程归档，并生成了复盘：</p><ul><li>选题来源：热点（OpenAI新模型）</li><li>fit-check 结果：通过</li><li>审核意见：3条</li><li>改写轮次：1轮</li><li>耗时：约40分钟</li></ul><p>整个过程，从看到热点到发布包生成，不到一小时。</p><hr><h2 id="另一个故事-热点被放弃" tabindex="-1">另一个故事：热点被放弃 <a class="header-anchor" href="#另一个故事-热点被放弃" aria-label="Permalink to &quot;另一个故事：热点被放弃&quot;">​</a></h2><p>热点不是每次都要跟。让我给你讲一个「放弃」的故事。</p><h3 id="第一步-发现热点-1" tabindex="-1">第一步：发现热点 <a class="header-anchor" href="#第一步-发现热点-1" aria-label="Permalink to &quot;第一步：发现热点&quot;">​</a></h3><p>周五下午，团队讨论要不要跟一个热点：「某明星官宣新恋情」。</p><p>团队的运营同事很兴奋：「这个热点流量超大，我们必须蹭一下！」</p><p>你觉得有点奇怪：我们是写 AI 效率的账号啊，跟明星恋情有什么关系？</p><p>但你又说不过他们。运营同事的理由是：「流量大啊，不蹭白不蹭。」</p><p>你说：「这样吧，我们用工作流来分析一下，让数据说话。」</p><h3 id="第二步-发起热点-1" tabindex="-1">第二步：发起热点 <a class="header-anchor" href="#第二步-发起热点-1" aria-label="Permalink to &quot;第二步：发起热点&quot;">​</a></h3><p>你说：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/xhs:hot</span></span>
<span class="line"><span></span></span>
<span class="line"><span>主题：某明星官宣新恋情</span></span>
<span class="line"><span>来源：微博热搜</span></span>
<span class="line"><span>紧急度：medium</span></span></code></pre></div><p>AI 生成了 fit-check.md。</p><p>你打开一看：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## 适切性分析</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### 相关性评估</span></span>
<span class="line"><span>- 领域相关度：极低</span></span>
<span class="line"><span>- 受众匹配度：低（我们的受众是程序员和效率爱好者）</span></span>
<span class="line"><span>- 时间窗口：中等</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### 风险提示</span></span>
<span class="line"><span>- 强行跟热点会显得刻意</span></span>
<span class="line"><span>- 可能会伤害品牌调性——读者会疑惑「这个账号怎么开始追星了」</span></span>
<span class="line"><span>- 就算流量高，转化率也会很低</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### 建议</span></span>
<span class="line"><span>放弃。或者，如果非要跟，可以用一种完全不同的方式（比如「从程序员角度看这个公告的语法错误」），但风险较大</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### 结论</span></span>
<span class="line"><span>不建议跟，建议放弃</span></span></code></pre></div><h3 id="第三步-放弃" tabindex="-1">第三步：放弃 <a class="header-anchor" href="#第三步-放弃" aria-label="Permalink to &quot;第三步：放弃&quot;">​</a></h3><p>你把这个分析给团队看了。</p><p>运营同事看完之后说：「好吧，确实不太搭。万一读者取关就亏了。」</p><p>于是你说：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/xhs:fit rejected</span></span>
<span class="line"><span>/xhs:archive --outcome dropped</span></span></code></pre></div><p>这个决策过程被完整记录了下来。下次再有人提议跟热点，直接调出这份记录：「上次分析过了，不适合。」</p><p>这就是 Trend 工作流的价值：<strong>它不是阻止你追热点，而是让你在追热点之前，先冷静三秒钟。</strong></p><hr><h2 id="交互方式" tabindex="-1">交互方式 <a class="header-anchor" href="#交互方式" aria-label="Permalink to &quot;交互方式&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/xhs:hot                              # 发起热点</span></span>
<span class="line"><span>/xhs:fit approved                     # 适切性通过</span></span>
<span class="line"><span>/xhs:fit rejected                     # 适切性拒绝</span></span>
<span class="line"><span>/xhs:review                           # 审核草稿</span></span>
<span class="line"><span>/xhs:rewrite                          # 改写（如需要）</span></span>
<span class="line"><span>/xhs:publish                          # 生成发布包</span></span>
<span class="line"><span>/xhs:archive --outcome dropped       # 归档（放弃热点）</span></span></code></pre></div><hr><h2 id="状态流转" tabindex="-1">状态流转 <a class="header-anchor" href="#状态流转" aria-label="Permalink to &quot;状态流转&quot;">​</a></h2><h3 id="热点通过" tabindex="-1">热点通过 <a class="header-anchor" href="#热点通过" aria-label="Permalink to &quot;热点通过&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>initialized → fit-checking → fit-approved → drafting → reviewed → done → archived</span></span></code></pre></div><table tabindex="0"><thead><tr><th>状态</th><th>意味着什么</th></tr></thead><tbody><tr><td><code>initialized</code></td><td>热点已创建，trend-brief 正在形成</td></tr><tr><td><code>fit-checking</code></td><td>正在判断热点与品牌是否匹配</td></tr><tr><td><code>fit-approved</code></td><td>允许进入草稿阶段</td></tr><tr><td><code>drafting</code></td><td>初稿正在撰写</td></tr><tr><td><code>reviewed</code></td><td>审核意见已经给出</td></tr><tr><td><code>done</code></td><td>发布包已经生成</td></tr><tr><td><code>archived</code></td><td>经验已经沉淀到知识库</td></tr></tbody></table><h3 id="热点放弃" tabindex="-1">热点放弃 <a class="header-anchor" href="#热点放弃" aria-label="Permalink to &quot;热点放弃&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>initialized → fit-checking → fit-rejected → archived</span></span></code></pre></div><table tabindex="0"><thead><tr><th>状态</th><th>意味着什么</th></tr></thead><tbody><tr><td><code>initialized</code></td><td>热点已创建</td></tr><tr><td><code>fit-checking</code></td><td>正在判断适切性</td></tr><tr><td><code>fit-rejected</code></td><td>热点被放弃</td></tr><tr><td><code>archived</code></td><td>决策过程已归档，经验沉淀</td></tr></tbody></table><hr><h2 id="为什么-fit-check-不能省" tabindex="-1">为什么 fit-check 不能省 <a class="header-anchor" href="#为什么-fit-check-不能省" aria-label="Permalink to &quot;为什么 fit-check 不能省&quot;">​</a></h2><p>我知道你在想什么：「不就是追个热点吗，有必要这么复杂吗？」</p><p>让我告诉你为什么。</p><h3 id="热点是最容易让人冲动的场景" tabindex="-1">热点是最容易让人冲动的场景 <a class="header-anchor" href="#热点是最容易让人冲动的场景" aria-label="Permalink to &quot;热点是最容易让人冲动的场景&quot;">​</a></h3><blockquote><p>「先写了再说，管它搭不搭呢。」</p></blockquote><p>这是很多运营人员追热点时的心声。然后呢？</p><ul><li>写了两小时，发出去没人看</li><li>流量很高，但转化率为零</li><li>读者开始疑惑：「这个账号到底是干嘛的」</li><li>甚至被老读者取关：「你怎么变成这样了」</li></ul><p>热点之所以危险，是因为它<strong>自带流量，让人看不清风险</strong>。</p><h3 id="fit-check-强制你停下来想三秒" tabindex="-1">fit-check 强制你停下来想三秒 <a class="header-anchor" href="#fit-check-强制你停下来想三秒" aria-label="Permalink to &quot;fit-check 强制你停下来想三秒&quot;">​</a></h3><p>这四个问题必须想清楚：</p><ol><li><strong>跟我的品牌有没有关系？</strong> —— 不要强行关联</li><li><strong>对我的受众有没有价值？</strong> —— 不要自嗨</li><li><strong>有没有合规风险？</strong> —— 不要踩红线</li><li><strong>我能不能写出差异化角度？</strong> —— 不要硬蹭</li></ol><p>这四个问题想清楚了，后续的创作效率才会高。</p><h3 id="放弃也是好决策" tabindex="-1">放弃也是好决策 <a class="header-anchor" href="#放弃也是好决策" aria-label="Permalink to &quot;放弃也是好决策&quot;">​</a></h3><p>记住：<strong>不是每个热点都值得跟。</strong></p><p>放弃一个热点，不是失败，而是理性的选择。Trend 工作流帮你记录了这个决策过程，让你可以理直气壮地说：「我们分析过了，不适合。」</p><hr><h2 id="quick-vs-trend-什么时候该用哪个" tabindex="-1">Quick vs Trend：什么时候该用哪个 <a class="header-anchor" href="#quick-vs-trend-什么时候该用哪个" aria-label="Permalink to &quot;Quick vs Trend：什么时候该用哪个&quot;">​</a></h2><table tabindex="0"><thead><tr><th>场景</th><th>推荐工作流</th></tr></thead><tbody><tr><td>突然有个想法想记录</td><td>Quick</td></tr><tr><td>日常更新，没有系列规划</td><td>Quick</td></tr><tr><td>热点来了，想快速响应</td><td>Trend</td></tr><tr><td>想测试某个角度有没有人看</td><td>Trend</td></tr><tr><td>已经有明确的系列计划</td><td>Campaign</td></tr></tbody></table><p>简单来说：</p><ul><li><strong>Quick</strong> = 你有一个想法</li><li><strong>Trend</strong> = 热点来了，你要判断该不该跟</li><li><strong>Campaign</strong> = 你有一个计划</li></ul>`,106)])])}const b=s(p,[["render",i]]);export{u as __pageData,b as default};
